import React, { useState } from 'react';
import { Bot, CalendarDays, Database, Play, AlertCircle, CheckCircle2, ClipboardPaste } from 'lucide-react';

export default function App() {
  const [activeTab, setActiveTab] = useState('fcst');
  const [status, setStatus] = useState({ type: 'idle', message: '' });

  return (
    <div className="flex h-screen bg-gray-50 font-sans">
      {/* 사이드바 */}
      <aside className="w-64 bg-[#1a233a] text-gray-300 flex flex-col shadow-xl">
        <div className="h-16 flex items-center px-6 bg-[#111827] border-b border-gray-700">
          <span className="text-xl font-bold text-white flex items-center gap-2">
            <Bot className="text-blue-400 w-6 h-6" /> Team AI Portal
          </span>
        </div>
        <nav className="flex-1 py-4">
          <button onClick={() => setActiveTab('fcst')} className={`w-full flex items-center gap-3 px-6 py-3 text-sm transition-colors ${activeTab === 'fcst' ? 'bg-blue-600/20 text-blue-400 border-r-4 border-blue-400 font-bold' : 'hover:bg-gray-800'}`}>
            <CalendarDays className="w-4 h-4" /> FCST & LOT 스케줄러
          </button>
          <button onClick={() => setActiveTab('master')} className={`w-full flex items-center gap-3 px-6 py-3 text-sm transition-colors ${activeTab === 'master' ? 'bg-blue-600/20 text-blue-400 border-r-4 border-blue-400 font-bold' : 'hover:bg-gray-800'}`}>
            <Database className="w-4 h-4" /> 관리자 (Master Data) 설정
          </button>
        </nav>
      </aside>

      {/* 메인 화면 */}
      <main className="flex-1 p-8 overflow-y-auto">
        <h2 className="text-2xl font-bold text-gray-800 mb-6">
          {activeTab === 'fcst' ? 'FCST 자동 스케줄링 워크스페이스' : '시스템 관리자 설정'}
        </h2>

        {activeTab === 'fcst' && (
          <div className="max-w-4xl space-y-6">
            <div className="grid grid-cols-2 gap-6">
              <div className="bg-white p-4 rounded-xl shadow-sm border">
                <h3 className="font-bold mb-2 flex items-center gap-2"><ClipboardPaste size={16}/> STEP 1. 신규 FCST</h3>
                <textarea className="w-full h-40 border-0 bg-gray-50 p-2 text-xs" placeholder="붙여넣기..."></textarea>
              </div>
              <div className="bg-white p-4 rounded-xl shadow-sm border">
                <h3 className="font-bold mb-2 flex items-center gap-2"><ClipboardPaste size={16}/> STEP 2. 기존 SOMP</h3>
                <textarea className="w-full h-40 border-0 bg-gray-50 p-2 text-xs" placeholder="붙여넣기..."></textarea>
              </div>
            </div>
            <button onClick={() => setStatus({type: 'success', message: '배정 완료'})} className="bg-blue-600 text-white px-8 py-3 rounded-lg font-bold hover:bg-blue-700 flex items-center gap-2">
              <Play size={16} /> 자동 배정 시작
            </button>
            {status.message && (
              <div className="p-4 bg-green-50 text-green-700 rounded-lg flex items-center gap-2"><CheckCircle2 size={16}/> {status.message}</div>
            )}
          </div>
        )}
      </main>
    </div>
  );
}
